#!/usr/bin/env bash
# agent-0-ship-high-decay.sh — Agent 产品从 0 到可 ship（high decay） SOP walkthrough for AI 产品经理 (LLM 应用 / 生成式 AI / Agent 产品 / Copilot 嵌入 — 跨模型评估 / 工作流设计 / 产品-工程协同).
# Auto-generated by cli_writer.py. Source: research/03-workflows.md.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="AI 产品经理 (LLM 应用 / 生成式 AI / Agent 产品 / Copilot 嵌入 — 跨模型评估 / 工作流设计 / 产品-工程协同)"
WORKFLOW="Agent 产品从 0 到可 ship（high decay）"

usage() {
  cat <<EOF
agent-0-ship-high-decay.sh — Walk through "${WORKFLOW}" SOP for ${INDUSTRY}

逐步走完这个工作流的入门 SOP, 然后做失败模式自检, 输出走查报告。

USAGE:
  ./agent-0-ship-high-decay.sh             # interactive
  ./agent-0-ship-high-decay.sh --dry-run
  ./agent-0-ship-high-decay.sh --json
  ./agent-0-ship-high-decay.sh --explain
  ./agent-0-ship-high-decay.sh --help
EOF
}

explain() {
  cat <<'EOT'
这个 SOP 走查脚本帮你完成 "Agent 产品从 0 到可 ship（high decay）" 工作流。

一句话: 当需求确实需要「LLM 自主决定用什么工具、多步执行」时，从「想做个 agent」到「一个通过 pass^k 可靠性门、有失败回退和用户控制权设计的 agent 产品」。

入门 SOP 共 6 步, 失败模式自检 4 项。

相关心智模型:
  • Eval 是地基,不是可选项（别 vibe-check）: 「AI 产品的『好』不是看几个 case 觉得行就 ship —— 是先针对你**自己产品的失败模式**建一套可重复、可回归的系统化测量;没有 eval 就是在瞎改。」
  • 先 error analysis,再加功能（PM 亲自看 trace）: 「质量上不去时,资深 AI PM 的第一反应**不是加功能**,是 PM 亲自拉 10-50 个真实 trace（trace 条数量级见 Hamel field-guide T03-S001 / ev

来源: research/03-workflows.md.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a SOP_STEPS=(
  "**先判断：真的需要 agent 吗**：过 workflow vs agent 的判断——多数需求其实是预定义路径的 workflow，agent 只在「路径无法预先定义」时才值得。PM 主导。跳过 → 把一个 routing workflow 做成 agent，无谓的不可靠 + 成本。 (evidence: [T03-S002])"
  "**能用 workflow 就用 workflow 五模式**：prompt chaining / routing / parallelization / orchestrator-workers / evaluator-optimizer，挑匹配的。PM + 工程师。跳过 → 重新发明 Anthropic 已经验证的模式。 (evidence: [T03-S002])"
  "**从 LLM API 直接起步，不先上框架**：很多模式几行代码就能实现；用框架也要懂底层。PM 认知 + 工程师实现。跳过 → 框架抽象遮住 prompt 和响应，debug 变难（intake「2023 LangChain 经典写法 2025 被批过度抽象」）。 (evidence: [T03-S002])"
  "**工具工程 = prompt 工程同等投入**：工具文档要写好、参数设计要「防呆」（Poka-yoke），跑大量样例输入找模型用工具时的错。PM 提需求 + 工程师实现。跳过 → agent 调工具频繁出错，根因是工具接口烂不是模型笨。 (evidence: [T03-S002])"
  "**沙箱里大量测试 + 加 guardrails**：在隔离环境跑大量 case，配 guardrails（tripwire 机制）。PM 定测试场景 + 工程师建。跳过 → 直接上生产，agent 越权 / 工具链被攻击。 (evidence: [T03-S002])"
  "**用 pass^k 而非单次 demo 作 ship 门**：上线标准是「同任务跑 k 次的稳定通过率」。PM 定门槛。跳过 → demo 美、生产崩（τ-bench：SOTA agent 零售域 pass^8 < 25%）。 (evidence: [T03-S002] + 04-canon τ-bench)"
)
declare -a FAILURE_MODES=(
  "**把不是 agent 的需求做成 agent**：触发原因 = 「agentic」是 2025-2026 最滥用前缀;怎么避免 = step 1 强制过 workflow vs agent 判断，默认假设是 workflow。（**CLI 自检项**：Can this task run on a predefined code path? If yes — build a workflow, not an agent. Most needs are workflows.） (evidence: [T03-S002])"
  "**一上来上重框架**：触发原因 = 觉得框架「专业」;怎么避免 = 从 LLM API 直接起步，几行代码能实现的不上框架。（**CLI 自检项**：Did you reach for a framework before trying the raw LLM API? Many agent patterns are a few lines of code — frameworks obscure debugging.） (evidence: [T03-S002])"
  "**工具文档糊弄、不做 Poka-yoke**：触发原因 = 觉得调 prompt 才是重点;怎么避免 = 工具工程投入对标 prompt 工程。（**CLI 自检项**：Did you spend as much effort on tool docs/interfaces as on prompts? Bad tool design — not a \"dumb model\" — causes most tool-call errors.） (evidence: [T03-S002])"
  "**用单次 demo 作 ship 门**：触发原因 = demo 跑通了很兴奋;怎么避免 = ship 门改成 pass^k 多次运行稳定通过率。（**CLI 自检项**：Is your ship criterion \"the demo worked\"? Replace it with pass^k — run the same task k times and measure stable success rate.） (evidence: [T03-S002] + 04-canon τ-bench)"
)
declare -a STEP_STATUS=()
declare -a STEP_NOTES=()
declare -a FAIL_CHECK=()

ms_section "${INDUSTRY} · ${WORKFLOW} 走查"
ms_info "逐步走完 ${#SOP_STEPS[@]} 步入门 SOP。每步可标 done / skipped / blocked。"
echo

for i in "${!SOP_STEPS[@]}"; do
  ms_section "Step $((i+1))/${#SOP_STEPS[@]}: ${SOP_STEPS[$i]}"
  ms_prompt "状态? [d=done / s=skipped / b=blocked]"
  read -r status
  STEP_STATUS+=("${status:-d}")
  case "${status:-d}" in
    s) ms_prompt "跳过原因 (一句话):"; read -r note ;;
    b) ms_prompt "blocker (一句话):"; read -r note ;;
    *) note="" ;;
  esac
  STEP_NOTES+=("$note")
done

if [[ ${#FAILURE_MODES[@]} -gt 0 ]]; then
  ms_section "失败模式自检"
  for fm in "${FAILURE_MODES[@]}"; do
    if ms_confirm "你是否避免了 — '$fm' ?"; then
      FAIL_CHECK+=("✓ $fm")
    else
      FAIL_CHECK+=("✗ $fm")
    fi
  done
fi

ms_buffer_append "# ${INDUSTRY} — ${WORKFLOW} 走查报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## SOP 步骤"
ms_buffer_append ""
for i in "${!SOP_STEPS[@]}"; do
  status_icon="?"
  case "${STEP_STATUS[$i]}" in
    d|D) status_icon="✓" ;;
    s|S) status_icon="↷" ;;
    b|B) status_icon="✗" ;;
  esac
  if [[ -n "${STEP_NOTES[$i]}" ]]; then
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]} — ${STEP_NOTES[$i]}"
  else
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]}"
  fi
done
ms_buffer_append ""
if [[ ${#FAIL_CHECK[@]} -gt 0 ]]; then
  ms_buffer_append "## 失败模式自检"
  ms_buffer_append ""
  for line in "${FAIL_CHECK[@]}"; do
    ms_buffer_append "- $line"
  done
  ms_buffer_append ""
fi

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "workflow" "${WORKFLOW}" \
    "step_count" "${#SOP_STEPS[@]}" \
    "failure_check_count" "${#FAILURE_MODES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "agent-0-ship-high-decay-walkthrough"
fi
